UPDATE demand
title=#{title}, description=#{description}, type=#{type}, priority=#{priority}, status=#{status}, project_id=#{projectId}, module_id=#{moduleId}, iteration_id=#{iterationId}, assignee_id=#{assigneeId}, reviewer_id=#{reviewerId}, approver_id=#{approverId}, estimated_hours=#{estimatedHours}, actual_hours=#{actualHours}, story_points=#{storyPoints}, expected_start_date=#{expectedStartDate}, expected_end_date=#{expectedEndDate}, actual_start_date=#{actualStartDate}, actual_end_date=#{actualEndDate}, approve_time=#{approveTime}, start_develop_time=#{startDevelopTime}, start_test_time=#{startTestTime}, complete_time=#{completeTime}, approve_comment=#{approveComment}, reject_reason=#{rejectReason}, acceptance_criteria=#{acceptanceCriteria}, acceptance_result=#{acceptanceResult}, version=#{version}, source=#{source}, business_value=#{businessValue}, technical_solution=#{technicalSolution}, risk_description=#{riskDescription}, update_time=#{updateTime}
WHERE id=#{id}

mapper.select:
SELECT d.*,
p.real_name AS creatorName,
a.real_name AS assigneeName,
ap.real_name AS approverName,
m.name as moduleName
FROM demand d
LEFT JOIN sys_user p ON d.creator_id = p.id
LEFT JOIN sys_user a ON d.assignee_id = a.id
LEFT JOIN sys_user ap ON d.approver_id = ap.id
LEFT JOIN project_module m ON d.module_id = m.id
WHERE 1=1

    AND (d.title LIKE CONCAT('%', #{keyword}, '%') OR d.description LIKE CONCAT('%', #{keyword}, '%'))

AND d.type = #{type}
AND d.priority = #{priority}
AND d.status = #{status}
AND d.creator_id = #{proposerId}
AND d.assignee_id = #{assigneeId}
ORDER BY d.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM demand WHERE delete_time IS NULL

