AND assignee_id = #{assigneeId}

SELECT d.*,
p.real_name AS creatorName,
a.real_name AS assigneeName,
pr.name AS projectName,
m.name AS moduleName,
i.name AS iterationName
FROM demand d
LEFT JOIN sys_user p ON d.creator_id = p.id
LEFT JOIN sys_user a ON d.assignee_id = a.id
LEFT JOIN sys_project pr ON d.project_id = pr.id
LEFT JOIN project_module m ON d.module_id = m.id
LEFT JOIN sys_iteration i ON d.iteration_id = i.id
WHERE d.delete_time IS NULL

